linear-gradient(to right,  rgba(11, 11, 11, 0.035) 1px, transparent 1px) 0 0 / 32px 32px,
    linear-gradient(to bottom, rgba(11, 11, 11, 0.035) 1px, transparent 1px) 0 0 / 32px 32px,
    var(--vision-paper)
